// Script Continued Below
var ClientTaskTemplateHelpers = Class.create();
ClientTaskTemplateHelpers.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	getTaskUIActionParamaters: function (){
		var task_id = this.getParameter('sysparm_task_id');
		var action_name = this.getParameter('sysparm_action_name');
		var action_guid; // not needed
		var actionParameters = new api_tasker_template().getUIActionParamaters(task_id, action_name, action_guid);
		var sActionParameters = JSON.stringify(actionParameters);
		return sActionParameters;
	}, 

	// 2.7.1 | 2021-11-27 | raj  | STRY0114396 - New function to set default Primary Assignee
	// NOTE, caller should only provide task id if the form does not have restricted group on it
	getTemplateDefaultPrimaryAssignee: function (){
		var arrUtil = new global.ArrayUtil();
		var default_primary_assignee = '';
		var sys_id = this.getParameter('sysparm_sys_id');
		var table = this.getParameter('sysparm_table');
		var restricted_group = this.getParameter('sysparm_restricted_group');
		// DFCT0011850 - need to pass Primary office into
		var primary_office = this.getParameter('sysparm_primary_office');
		var recordPrivacy = this.getParameter('sysparm_record_privacy');
		var assigned_member = this.getParameter('sysparm_assigned_member');
		var template = this.getParameter('sysparm_template');
		var template_level = this.getParameter('sysparm_template_level');
		var template_ou = this.getParameter('sysparm_template_ou');
		// if assigned_member passed as blank, do nothing
		if(assigned_member && assigned_member != ''){
			if((sys_id && sys_id != '-1')){
				var restricted_group_field_name;
				var grTempRec = new GlideRecordSecure(table);
				var tempDef = '';

				// get task record and see if restricted group is set
				if(grTempRec.get(sys_id)){
				// if restricted is blank and sys_id is not, then the form didn't have restricted group, look up in task record
				// NOTE, caller should only provide task id if the form does not have restricted group on it
					if( (!restricted_group || restricted_group == '')){
						switch(table){
							case 'x_153465_discovert_discover_routing_template':
								restricted_group_field_name = 'u_restricted_group';
								tempDef = sys_id;
								break;
							case 'x_153465_discovert_discover_routing_runtime':
								restricted_group_field_name = 'u_restricted_group';
								tempDef = grTempRec.getValue('routing_template_ref');
								break;
							case 'x_153465_discovert_route_tasks':
								restricted_group_field_name = 'assigned_to_group';
								tempDef = grTempRec.getValue('tasker_process_definition');
								break;
						}
						restricted_group = grTempRec.getValue(restricted_group_field_name)==null ? '' : grTempRec.getValue(restricted_group_field_name) + '';
					}
					var grTempDef = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
					if( (!template_level || template_level == '')){
						switch(table){
							case 'x_153465_discovert_discover_routing_template':
								template_level = grTempRec.getValue('process_level');
								break;
							case 'x_153465_discovert_route_tasks':
							case 'x_153465_discovert_discover_routing_runtime':
								if(grTempDef.get(tempDef)){
									template_level = grTempDef.getValue('process_level');
									template_level = grTempDef.getValue('process_level');
								}
								break;
						}
					}
					if( (!template_ou || template_ou == '') && template_level == 'ou_process'){
						switch(table){
							case 'x_153465_discovert_discover_routing_template':
								template_ou = grTempRec.getValue('process_ou');
								break;
							case 'x_153465_discovert_route_tasks':
							case 'x_153465_discovert_discover_routing_runtime':
								if(grTempDef.get(tempDef)){
									template_ou = grTempDef.getValue('process_ou');
								}
						}
					}
				}
			}
			// get list of ous the user can task based on and assigned member
			// DFCT0011850 - need to pass Primary office and recordPriave
			var aOUs = new taskerDynamicFilters().getTemplateOfficeArray('internal', primary_office, assigned_member, recordPrivacy, restricted_group, template_level, template_ou);
			// get user's default ou
			var defaultOU = new OrganizationalScripts().GetUserDefaultOU(assigned_member);
			// if user can task default ou of the assigned member, then return it
			if(arrUtil.indexOf(aOUs, defaultOU)>= 0){
				default_primary_assignee = defaultOU;
			} else {
				aOUs.sort();
				if(aOUs.length > 0){
					default_primary_assignee = aOUs[0];
				}
			}
		}
		return default_primary_assignee;
	},
	// STRY0085078 - TUP - Add Reviewer field on Template Instance - Controlled Organization Tasking Permissions
	getTemplateTopTaskerType: function(){
		var templateId = this.getParameter('templateId');
		var topTaskerTypeDiisplayValue = '';
		var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');

		if(grTemp.get(templateId)){
			// STRY0127550 - get the value instead of the display value and compare to a constant instead of a hard coded string
			topTaskerTypeDiisplayValue = grTemp.getDisplayValue("tasker_type.u_value");
		}
		return topTaskerTypeDiisplayValue;
	},

	// STRY0076609 - check the sub tasks and the current task to see if they are review item types 
	checkForApprovalTypeOnTaskTempAndSubTaskTemp: function(){
		var taskTempId = this.getParameter('taskTempId');
		var isReviewTypeWithChildReviewtype = false;
		var grTaskTemp = new GlideRecordSecure('x_153465_discovert_route_tasks');
		if(grTaskTemp.get(taskTempId)){
			if(grTaskTemp.u_wait_for_subtasks_to_finish  && grTaskTemp.work_item_type == "review_item"){
				var grSubTaskTemps = new GlideRecordSecure('x_153465_discovert_route_tasks');
				grSubTaskTemps.addQuery('parent', taskTempId);
				grSubTaskTemps.addQuery('work_item_type', "review_item");
				grSubTaskTemps.query();
				while (grSubTaskTemps.next()){
					if(grSubTaskTemps.u_wait_for_subtasks_to_finish){
						isReviewTypeWithChildReviewtype = true;
						break;
					}
				}
			}
		}
		return isReviewTypeWithChildReviewtype;
	},


	// - STRY0075793 - Patch 2.5.13 allow start template and run template modals to be called from Native pages
	loadTemplateAndTaskIntoInstanceForm: function(){
		var fields = this.getParameter('fields');
		var templateId = this.getParameter('templateId');
		var parentTaskId = this.getParameter('parentTaskId');
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.loadTemplateAndTaskIntoInstanceForm(fields, templateId, parentTaskId));
	},

	// - STRY0075793 - Patch 2.5.13 allow start template and run template modals to be called from Native pages
	loadTemplateIntoInstanceForm: function(){
		var fields = this.getParameter('fields');
		var templateId = this.getParameter('templateId');
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.loadTemplateIntoInstanceForm(fields, templateId));
	},

	// STRY0079327 - get start template on task working on backend form
	startTemplateWithID: function(){
		var templateInputs = this.getParameter('templateInputs');
		var oTemplateInputs = JSON.parse(templateInputs);
		var template = this.getParameter('template'); 
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.startTemplateWithID(template, true, oTemplateInputs));
	}

	// ***********************************************************************************************
	// DEPCRECATED IN 2.7 - MOVING AWAY FROM WORKFLOW MADE THIS UNNECCESSARY
	// EVERYTHING BELOW HERE WAS DEPRECATED
