	// STRY0079327 - get start template on task working on backend form
	//loadTemplateInputsFromDataFields: function(){
	//	var fields = this.getParameter('fields');
	//	var oFileds = JSON.parse(fields);
	//	var tTH = new TaskTemplateHelpers();
	//	return JSON.stringify(tTH.loadTemplateInputsFromDataFields(oFileds));
	//},	
